sys_script.script:
/**
 * 2026/05/06 Quynhttn_TAM29_Automation update for TOF field in BID Presales Table
 * Async Business Rule: BID Presales Time Calculation
 * 
 * Logic:
 * - Retrieve Ticket Date (u_start_date) from Recruitment Request
 * - Calculate difference between Submit Date and Ticket Date
 * - Convert result from seconds to days
 * - Store value in time_of_submitting field
 *
 * @param {GlideRecord} current - Current record (BID Presales)
 * @param {GlideRecord} previous - Previous record (null when async)
 */
(function executeRule(current, previous /*null when async*/) {
	// Get related Recruitment Request record
	var recruitmentGR = new GlideRecord('x_1763182_talent_0_recruitment_request');
	recruitmentGR.get(current.getValue('u_bid_recruit_id'));

	// Retrieve date values from table Recruiment Request in Start Date filed
    var ticketGDT = new GlideDateTime(recruitmentGR.getValue('u_start_date'));

	// Retrieve date values from table BID Presales in Submit Date
	var submitGDT = new GlideDateTime(current.getValue('u_actual_start_date'));

	// Calculate time of submitting
	var timeOfSubmitting = GlideDateTime.subtract(ticketGDT, submitGDT);

	// Convert milliseconds to days
	var timeOfSubmittingInDays = Math.floor(timeOfSubmitting.getNumericValue() / 86400000);
    if (isNaN(timeOfSubmittingInDays)) {
        gs.error('[TAM][Calculate TOF] Unable to calculate Time of Submitting: Ticket Date: ' 
        + ticketGDT + ', Submit Date: ' + submitGDT + ', Days: ' + timeOfSubmittingInDays);
		return;
    }

	// Set calculated value to table BID Presales in Time of submitting field
    current.setValue('time_of_submitting', timeOfSubmittingInDays);

	// Determine TOF choice value
    var tofValue = '';

    switch (true) {

        case (timeOfSubmittingInDays < 1):
            tofValue = 'less_than_1';
            break;

        case (timeOfSubmittingInDays <= 3):
            tofValue = '1_to_3_days';
            break;

        case (timeOfSubmittingInDays <= 5):
            tofValue = '3_to_5_days';
            break;

        case (timeOfSubmittingInDays <= 7):
            tofValue = '5_to_7_days';
            break;

        case (timeOfSubmittingInDays <= 15):
            tofValue = '7_to_15_days';
            break;

        case (timeOfSubmittingInDays <= 30):
            tofValue = '15_to_30_days';
            break;

        default:
            tofValue = 'more_than_30';
    }

    // Set TOF choice field
    current.setValue('u_bid_tof', tofValue);

	// Update BID Presales table
    current.update();
})(current, previous);
